// n8n Code / Function Node
// Input: WHO ICD API JSON (single item)

const input = $input.first().json;

// Safely access title.@value
const cidDescription =
  input &&
  input.title &&
  typeof input.title === 'object' &&
  typeof input.title['@value'] === 'string'
    ? input.title['@value'].trim()
    : "";

// Build normalized output
return [
  {
    json: {
      cid_found: cidDescription !== "",
      cid_description: cidDescription
    }
  }
];

if (!$("Dados CNPJ").first().json.success) {
  return $("Dados CNPJ").first()
 } else {return JSON.parse('{}')}

/**
 * MIA-SADM — QR + HTTP Normalizer (STRICT)
 * INPUT 1 -> httpInput.statusCode
 * INPUT 2 -> qrInput (string JSON or object)
 */

// ================= INPUTS =================
const httpInput = $input.first().json; // HTTP Request
const qrInput   = $('Leitor de QR Code').first().json.stdout; // QR Reader
// ==========================================


// ---------------- Helpers ----------------
function parseJSONSafe(value) {
  if (typeof value === "object") return value;
  if (typeof value === "string") {
    try { return JSON.parse(value); } catch { return null; }
  }
  return null;
}

// ---------------- Output ----------------
const result = {
  qr_exists: false,
  qr_decodable: false,
  qr_target_url: "",
  qr_domain: "",
  qr_bbox: {
    x: 0,
    y: 0,
    width: 0,
    height: 0
  },
  qr_url_status: "error"
};

// ---------------- HTTP (STRICT) ----------------
if (httpInput && httpInput.statusCode === 200) {
  result.qr_url_status = "active";
}

// ---------------- QR (STRICT) ----------------
const qr = parseJSONSafe(qrInput);

if (qr) {
  result.qr_exists = qr.qr_exists === true;
  result.qr_decodable = qr.qr_decodable === true;
  result.qr_target_url = qr.qr_text || "";
  result.qr_domain = qr.qr_domain || "";

  if (qr.qr_bbox) {
    result.qr_bbox = {
      x: qr.qr_bbox.x ?? 0,
      y: qr.qr_bbox.y ?? 0,
      width: qr.qr_bbox.width ?? 0,
      height: qr.qr_bbox.height ?? 0
    };
  }
}

// ---------------- Final rule ----------------
if (!(result.qr_exists && result.qr_decodable && httpInput?.statusCode === 200)) {
  result.qr_url_status = "error";
}

// ---------------- Return ----------------
return [{ json: result }];

var data = $('Output Analise Imagem').first().json;

data.medical_professional.cfm_data = $('output CRM').first().json;

data.issuer_information.cnpj_data = $('Output CNPJ').first().json;

data.medical_classification.cid_oms_data = 
$('Output CID').first().json;

data.qr_validation.qr_code_data = $('Output QRCode').first().json;

// Só cria/atribui employe_data se "Output Analise Paciente" tiver conteúdo (não vazio)
const outPaciente = $("Output Analise Paciente").first()?.json;

// considera vazio se: null/undefined ou objeto sem chaves
const outPacienteVazio =
  !outPaciente ||
  (typeof outPaciente === "object" && !Array.isArray(outPaciente) && Object.keys(outPaciente).length === 0);

if (!outPacienteVazio) {
  // garante o caminho
  data.patient_identification = data.patient_identification || {};
  data.patient_identification.employe_data = outPaciente;
} else {
  // se por algum motivo já existir, remove
  if (data?.patient_identification && "employe_data" in data.patient_identification) {
    delete data.patient_identification.employe_data;
  }
}

return data;

// ============================================
// Recupera dados
// ============================================

// Resposta do HTTP Request (GET + Range bytes=0-0)
const response = $input.first().json;

// URL original enviada no payload
const urlImage = $('Edit Fields').first().json.url_image;

// ============================================
// Valida URL recebida
// ============================================

if (!urlImage) {
  return [
    {
      json: {
        isValid: false,
        status: 400,
        error: "URL da imagem não fornecida",
      },
    },
  ];
}

// ============================================
// Valida Status HTTP
// ============================================

// Sucesso pode ser 200 (OK) ou 206 (Partial Content)
const validStatusCodes = [200, 206];

if (!validStatusCodes.includes(response.statusCode)) {
  return [
    {
      json: {
        isValid: false,
        status: 400,
        url: urlImage,
        statusCode: response.statusCode,
        statusMessage: response.statusMessage,
        error: "URL não acessível (status inválido)",
      },
    },
  ];
}

// ============================================
// Valida Content-Type
// ============================================

const contentType =
  response.headers?.["content-type"] ||
  response.headers?.["Content-Type"] ||
  null;

// Extensões permitidas
const allowedExtensions = ["webp", "jpg", "jpeg", "png", "gif", "bmp"];

// Extrai extensão da URL sem querystring
const urlExtension = (() => {
  try {
    const cleanUrl = urlImage.split("?")[0];
    return cleanUrl.split(".").pop().toLowerCase();
  } catch {
    return "";
  }
})();

// Regras:
// - Content-Type deve começar com image/
// OU extensão deve ser conhecida
const isImageByContentType =
  contentType && contentType.startsWith("image/");

const isImageByExtension =
  allowedExtensions.includes(urlExtension);

// ⚠️ Aqui seu exemplo falharia porque veio application/pdf
if (!isImageByContentType && !isImageByExtension) {
  return [
    {
      json: {
        isValid: false,
        status: 400,
        url: urlImage,
        statusCode: response.statusCode,
        contentType,
        extension: urlExtension || null,
        error:
          "Arquivo acessível, mas não é uma imagem válida (Content-Type incorreto)",
      },
    },
  ];
}

// ============================================
// Gera FILE_PREFIX único
// ============================================

const now = new Date();
const pad = (n, size) => String(n).padStart(size, "0");

const timestamp =
  now.getFullYear() +
  pad(now.getMonth() + 1, 2) +
  pad(now.getDate(), 2) +
  pad(now.getHours(), 2) +
  pad(now.getMinutes(), 2) +
  pad(now.getSeconds(), 2) +
  pad(now.getMilliseconds(), 3);

const FILE_PREFIX = timestamp;

// ============================================
// Resultado FINAL (válido)
// ============================================

return [
  {
    json: {
      isValid: true,
      status: 200,
      url_final: urlImage,
      statusCode: response.statusCode, // 200 ou 206
      contentType,
      extension: urlExtension,
      FILE_PREFIX,
      message: "URL válida e acessível como imagem",
    },
  },
];

/**
 * MIA-SADM — Deterministic Decision & Scoring Engine v2.1.2
 * N8N-ready (drop-in replacement) — EVOLUTION of PROD v2.0.4
 *
 * Compatibility guarantee:
 * - When ENABLE_RULE_ENGINE_DEBUG = false, the output JSON structure remains identical to v2.0.4.
 * - Debug payload (_rule_engine_debug) may change freely.
 *
 * v2.1.1 changes (MINIMAL):
 * - Optional patient_identification.employe_data support:
 *    - If employe_data absent: NO CHANGE in behavior.
 *    - If employe_data present:
 *        - Patient vs Employee name match is CRITICAL acceptance (score >= 0.5).
 *        - all_documents_match === false => VERY HIGH penalty.
 *
 * v2.1.2 changes (MINIMAL):
 * - Optional forensic_analysis.scribbles_count:
 *    - Configurable min/max (defaults 3 and 6).
 *    - scribbles_count < min: no penalty (keeps eligible for auto).
 *    - min <= scribbles_count <= max: moderate penalty (scaled).
 *    - scribbles_count > max: critical (hard gate + high penalty).
 */

// =========================================================
// CONFIG
// =========================================================
const ENABLE_RULE_ENGINE_DEBUG = false; // base debug (run log)
const ENABLE_RULE_ENGINE_DEBUG_COVERAGE_MAP = false; // full catalog/config map
const ENABLE_RULE_ENGINE_DEBUG_RATIONALE_MAP = false; // full rationale dictionary + unmapped report

const ENGINE_VERSION = "v2.1.2";
const MAX_RATIONALE_ITENS = 5;

// =========================================================
// [MIN-CHANGE] NAME MATCHING SENSITIVITY (CFM match_score threshold)
// =========================================================
const NAME_MATCH_MIN_SCORE = 0.4; // <-- ajuste aqui
const NAME_MATCH_SCORE_NULL_IS_OK = true; // if match_score missing but match_status=matched, still accept

// =========================================================
// BUSINESS CONFIG (employee cross-check)
// =========================================================
const EMPLOYEE_NAME_MATCH_MIN_SCORE = 0.5; // critical threshold when employe_data exists

// =========================================================
// BUSINESS CONFIG (scribbles / rasuras)
// =========================================================
const SCRIBBLES_MIN = 2; // default
const SCRIBBLES_MAX = 6; // default

// =========================================================
// BUSINESS CONFIG (time rules)
// =========================================================
const MAX_DOCUMENT_AGE_DAYS_FOR_AUTO = 35; // <- ajuste aqui quando necessário

// =========================================================
// BUSINESS CONFIG (leave temporal consistency)
// =========================================================
const MAX_LEAVE_START_OFFSET_DAYS = 1;        // leave_start can be attendance_date or attendance_date + 1
const PTS_LEAVE_TEMPORAL_INCONSISTENCY = 60;  // high risk points (preserved)

// =========================================================
// BUSINESS CONFIG (score shaping)
// =========================================================
const BASE_RISK_SCORE = 8;      // makes 0 / 100 rare
const BONUS_CAP = -40;          // preserved

// =========================================================
// INPUT
// =========================================================
const inputRaw = $input.first().json;
const input = Array.isArray(inputRaw) ? (inputRaw[0] ?? {}) : (inputRaw ?? {});

// =========================================================
// HELPERS
// =========================================================
const isEmpty = (v) => v === "" || v === undefined || v === null;
const norm = (v) => (isEmpty(v) ? null : v);

function get(obj, path, fallback = null) {
  try {
    const parts = path.split(".");
    let cur = obj;
    for (const p of parts) {
      if (cur == null) return fallback;
      cur = cur[p];
    }
    return cur === undefined ? fallback : cur;
  } catch {
    return fallback;
  }
}

function toISODateFromBR(dateStr) {
  if (!dateStr || typeof dateStr !== "string") return null;
  const m = dateStr.trim().match(/^(\d{2})\/(\d{2})\/(\d{2}|\d{4})$/);
  if (!m) return null;

  const dd = parseInt(m[1], 10);
  const mm = parseInt(m[2], 10);
  let yy = m[3];
  if (yy.length === 2) yy = "20" + yy;
  const yyyy = parseInt(yy, 10);

  if (!(yyyy >= 2000 && yyyy <= 2099)) return null;
  if (!(mm >= 1 && mm <= 12)) return null;
  if (!(dd >= 1 && dd <= 31)) return null;

  const d = new Date(Date.UTC(yyyy, mm - 1, dd));
  if (isNaN(d.getTime())) return null;
  if (d.getUTCFullYear() !== yyyy || d.getUTCMonth() !== (mm - 1) || d.getUTCDate() !== dd) return null;

  return `${String(yyyy).padStart(4, "0")}-${String(mm).padStart(2, "0")}-${String(dd).padStart(2, "0")}`;
}

function isoDateOnlyUTC(d) {
  if (!d || isNaN(d.getTime())) return null;
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, "0");
  const da = String(d.getUTCDate()).padStart(2, "0");
  return `${y}-${m}-${da}`;
}

function todayISODateUTC() {
  const now = new Date();
  return isoDateOnlyUTC(now);
}

function evalISODateUTC() {
  const ts = norm(get(input, "document_metadata.analysis_timestamp", null))
    ?? norm(get(input, "document_metadata.analysisTimestamp", null));

  if (ts && typeof ts === "string") {
    const d = new Date(ts);
    const iso = isoDateOnlyUTC(d);
    if (iso) return iso;
  }
  return todayISODateUTC();
}

function parseISODateToUTC(isoDate) {
  if (!isoDate || typeof isoDate !== "string") return null;
  const m = isoDate.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!m) return null;
  const y = parseInt(m[1], 10);
  const mo = parseInt(m[2], 10);
  const da = parseInt(m[3], 10);
  const d = new Date(Date.UTC(y, mo - 1, da));
  if (isNaN(d.getTime())) return null;
  if (d.getUTCFullYear() !== y || d.getUTCMonth() !== (mo - 1) || d.getUTCDate() !== da) return null;
  return d;
}

function daysBetweenUTC(a, b) {
  const ms = b.getTime() - a.getTime();
  return Math.floor(ms / 86400000);
}

function clampScore(n) {
  const x = Number.isFinite(n) ? n : 0;
  return Math.max(0, Math.min(100, x));
}

function anyTrue(obj) {
  if (!obj || typeof obj !== "object") return false;
  return Object.values(obj).some((v) => v === true);
}

function hasQuestionMarks(name) {
  if (!name || typeof name !== "string") return false;
  return name.includes("?") || name.includes("�");
}

function inSet(v, arr) {
  return arr.includes(v);
}

function piecewiseDocAgePenalty(ageDays) {
  if (!Number.isFinite(ageDays)) return 0;
  if (ageDays <= MAX_DOCUMENT_AGE_DAYS_FOR_AUTO) return 0;
  if (ageDays <= 60) return 6;
  if (ageDays <= 120) return 12;
  if (ageDays <= 365) return 22;
  return 30;
}

function piecewiseCompletenessPenalty(v) {
  if (!Number.isFinite(v)) return 0;
  if (v < 0.60) return 28;
  if (v < 0.75) return 18;
  if (v < 0.85) return 12;
  if (v < 0.90) return 6;
  return 0;
}

function piecewiseQualityPenalty(v) {
  if (!Number.isFinite(v)) return 0;
  if (v < 0.60) return 15;
  if (v < 0.85) return 6;
  return 0;
}

function piecewiseConsistencyPenalty(v) {
  if (!Number.isFinite(v)) return 0;
  if (v < 0.75) return 10;
  if (v < 0.90) return 4;
  return 0;
}

function addPenalty(arr, code, points, evidence, meta = {}) {
  if (!Number.isFinite(points) || points <= 0) return;
  arr.push({ code, points, evidence: evidence || "", ...meta });
}

function addBonus(arr, code, points, evidence, meta = {}) {
  if (!Number.isFinite(points) || points >= 0) return;
  arr.push({ code, points, evidence: evidence || "", ...meta });
}

// =========================================================
// NORMALIZE / EXTRACT (authoritative structured fields)
// =========================================================
const documentType = norm(get(input, "document_metadata.document_type", null));
const isMedicalCertificate = get(input, "document_metadata.is_medical_certificate", false) === true;

const captureType = norm(get(input, "capture.capture_type", null));

const ocrConfidence = (() => {
  const v = get(input, "ocr.confidence_avg", null);
  if (v === null || v === undefined || v === "") return null;
  const num = Number(v);
  return Number.isFinite(num) ? num : null;
})();

const patientName = norm(get(input, "patient_identification.patient_name", null));
const patientDocValue = norm(get(input, "patient_identification.patient_document_value", null));

// --- employe_data (optional) ---
const employeDataRaw = get(input, "patient_identification.employe_data", null);
const employeDataPresent = !!(employeDataRaw && typeof employeDataRaw === "object");

const emp_patient_data_present = employeDataPresent ? (get(employeDataRaw, "patient_data_present", null) === true) : null;
const emp_employee_data_present = employeDataPresent ? (get(employeDataRaw, "employee_data_present", null) === true) : null;

const emp_name_score = (() => {
  if (!employeDataPresent) return null;
  const v = get(employeDataRaw, "patient_employee_name_score", null);
  const num = Number(v);
  return Number.isFinite(num) ? num : null;
})();

const emp_name_match = employeDataPresent ? (get(employeDataRaw, "patient_employee_name_match", null) === true) : null;

const emp_all_documents_match = employeDataPresent ? get(employeDataRaw, "all_documents_match", null) : null; // true|false|null

const emp_patient_document_present = employeDataPresent ? (get(employeDataRaw, "patient_document_present", null) === true) : null;
const emp_patient_employee_national_document_match = employeDataPresent ? get(employeDataRaw, "patient_employee_national_document_match", null) : null;
const emp_patient_employee_identity_document_match = employeDataPresent ? get(employeDataRaw, "patient_employee_identity_document_match", null) : null;

// Derived acceptance (critical when employe_data exists)
const employeeCrossCheckRequired = employeDataPresent === true; // exists => required
const employeeNameOk = (() => {
  if (!employeeCrossCheckRequired) return true; // no change if absent
  if (!Number.isFinite(emp_name_score)) return false;
  return emp_name_score >= EMPLOYEE_NAME_MATCH_MIN_SCORE;
})();
const employeeDocsOk = (() => {
  if (!employeeCrossCheckRequired) return true;
  if (emp_all_documents_match === null) return true; // null => no-op (insufficient data)
  return emp_all_documents_match === true;
})();

const issuerName = norm(get(input, "issuer_information.issuer_name", null));

// Prefer CFM doctor_name and crm_state when present
const cfmDoctorName = norm(get(input, "medical_professional.cfm_data.cfm_data.doctor_name", null));
const cfmCrmState   = norm(get(input, "medical_professional.cfm_data.cfm_data.crm_state", null));

const doctorNameRaw = norm(get(input, "medical_professional.doctor_name", null));
const doctorName = cfmDoctorName || doctorNameRaw;

const crmNumber = norm(get(input, "medical_professional.crm_number", null));
const crmStateFromOCR = norm(get(input, "medical_professional.crm_state", null));
const crmUF = cfmCrmState || crmStateFromOCR;

const attendanceType = norm(get(input, "attendance_information.attendance_type", null));
const attendanceDateBR = norm(get(input, "attendance_information.attendance_date", null));
const attendanceDateISO = toISODateFromBR(attendanceDateBR);

const periodoIndefinido = norm(get(input, "attendance_information.periodo_indefinido", null)); // e.g. "S"

const leave = get(input, "attendance_information.leave", {}) || {};
const leaveType = norm(get(leave, "type", null));
const leaveDays = (() => {
  const v = get(leave, "days", null);
  if (v === null || v === undefined || v === "") return null;
  const num = Number(v);
  return Number.isFinite(num) ? num : null;
})();
const leaveHours = (() => {
  const v = get(leave, "hours", null);
  if (v === null || v === undefined || v === "") return null;
  const num = Number(v);
  return Number.isFinite(num) ? num : null;
})();
const leaveDaysRisk = norm(get(leave, "leave_days_risk", null));
const leaveStartISO = toISODateFromBR(norm(get(leave, "start_date", null)));
const leaveEndISO = toISODateFromBR(norm(get(leave, "end_date", null)));
const leaveStartHour = norm(get(leave, "hours_start", null));
const leaveEndHour   = norm(get(leave, "hours_end", null));

const cidParent = norm(get(input, "medical_classification.cid_parent", null));
const cidType = norm(get(input, "medical_classification.cid_version", null));
const cidFound = get(input, "medical_classification.cid_oms_data.cid_found", null);
const cidValid = (() => {
  if (cidParent === null) return null;
  if (cidFound === true) return true;
  if (cidFound === false) return false;
  return null;
})();

const elements = get(input, "document_elements", {}) || {};
const hasMandatoryFields = get(elements, "has_mandatory_fields", false) === true;
const hasStamp = get(elements, "has_stamp", false) === true;
const hasSignature = get(elements, "has_signature", false) === true;
const stampValid = get(elements, "stamp_valid", false) === true;
const signatureValid = get(elements, "signature_valid", false) === true;

const hasDoctorData = get(elements, "has_doctor_data", false) === true;
const hasPatientData = get(elements, "has_patient_data", false) === true;
const hasDiseaseData = get(elements, "has_disease_data", false) === true;

const hasIssuerData = get(elements, "has_issuer_data", null);
const hasAttendanceData = get(elements, "has_attendance_data", null);
const hasLocalityData = get(elements, "has_locality_data", null);
const hasDisclaimer = get(elements, "has_disclaimer", null);

const qrExists = get(input, "qr_validation.qr_code_data.qr_exists", false) === true;
const qrDecodable = get(input, "qr_validation.qr_code_data.qr_decodable", false) === true;
const qrUrlStatus = norm(get(input, "qr_validation.qr_code_data.qr_url_status", null));

const forensic = get(input, "forensic_analysis", {}) || {};
const digitalManip = norm(get(forensic, "digital_manipulation_indicators", null));
const physicalManip = norm(get(forensic, "physical_manipulation_indicators", null));
const aiIndicators = norm(get(forensic, "ai_generation_or_reconstruction_indicators", null));

// NEW: scribbles_count (optional; NO CHANGE if absent)
const scribblesCount = (() => {
  const v = get(forensic, "scribbles_count", null);
  if (v === null || v === undefined || v === "") return null;
  const num = Number(v);
  return Number.isFinite(num) ? num : null;
})();

const forensicNotes = norm(get(forensic, "forensic_notes", null));
const visualIssues = get(forensic, "visual_quality_issues", {}) || {};
const anyVisualIssues = anyTrue(visualIssues);

const manipulation = get(input, "manipulation_analysis", {}) || {};
const manipulationDetected = get(manipulation, "detected", false) === true;

const imageScoresRaw = get(input, "image_scores", {}) || {};
const imageScores = {
  consistency: Number(get(imageScoresRaw, "consistency", 1)),
  completeness: Number(get(imageScoresRaw, "completeness", 1)),
  image_quality: Number(get(imageScoresRaw, "image_quality", 1)),
};

const preliminary = get(input, "preliminary_recommendation", {}) || {};
const visualRisk = norm(get(preliminary, "visual_risk", null)); // low|medium|high
const recommendedAction = norm(get(preliminary, "recommended_action", null)); // accept|reject (or others)
const visualReasonCode = norm(get(preliminary, "reason_code", null));

// CFM (authoritative when present)
const cfmSituation = norm(get(input, "medical_professional.cfm_data.cfm_data.situation", null));
const cfmMatchStatus = norm(get(input, "medical_professional.cfm_data.cfm_data.match_status", null))
  ?? norm(get(input, "medical_professional.cfm_data.match_status", null));
const cfmMatchScore = (() => {
  const v = get(input, "medical_professional.cfm_data.cfm_data.match_score", null);
  if (v === null || v === undefined || v === "") return null;
  const num = Number(v);
  return Number.isFinite(num) ? num : null;
})();

const crmPresent = crmNumber !== null;
const crmStatusNorm = (() => {
  if (cfmSituation === null) return "not_verified";
  return String(cfmSituation).toLowerCase() === "active" ? "active" : "inactive";
})();

const crmStateFromCFM = norm(get(input, "medical_professional.cfm_data.cfm_data.crm_state", null));
const crmStateResolved = crmStateFromCFM || crmStateFromOCR;

const crmVerifiedAndValid = (() => {
  const hasName = doctorName !== null;
  const hasCRM = crmNumber !== null;

  const ufOk = crmStateResolved !== null && String(crmStateResolved).trim().length === 2;
  const situationOk = crmStatusNorm === "active";
  const matchOk = String(cfmMatchStatus || "").toLowerCase() === "matched";

  const scoreOk = (cfmMatchScore === null)
    ? (NAME_MATCH_SCORE_NULL_IS_OK === true)
    : (cfmMatchScore >= NAME_MATCH_MIN_SCORE);

  return hasName && hasCRM && ufOk && situationOk && matchOk && scoreOk;
})();

// =========================================================
// DATE RULES
// =========================================================
const evalISO = evalISODateUTC();
const dAtt = attendanceDateISO ? parseISODateToUTC(attendanceDateISO) : null;
const dEval = parseISODateToUTC(evalISO);

const attendanceAgeDays = (() => {
  if (!dAtt || !dEval) return null;
  return daysBetweenUTC(dAtt, dEval); // eval - attendance
})();

const isFutureAttendance = (() => {
  if (!dAtt || !dEval) return false;
  return dAtt.getTime() > dEval.getTime();
})();

const withinMaxAutoDays = (() => {
  if (attendanceAgeDays === null) return false;
  return attendanceAgeDays >= 0 && attendanceAgeDays <= MAX_DOCUMENT_AGE_DAYS_FOR_AUTO;
})();

// =========================================================
// LEAVE vs ATTENDANCE TEMPORAL CONSISTENCY (HIGH RISK)
// =========================================================
const dLeaveStart = leaveStartISO ? parseISODateToUTC(leaveStartISO) : null;

const leavePresent = (() => {
  const d = leaveDays ?? 0;
  const h = leaveHours ?? 0;
  const hasStart = !!leaveStartISO;
  const hasEnd = !!leaveEndISO;
  const hasWindow = (!!leaveStartHour || !!leaveEndHour);
  const indef = String(periodoIndefinido || "").toUpperCase() === "S";

  return (
    !!leaveType ||
    (Number.isFinite(d) && d > 0) ||
    (Number.isFinite(h) && h > 0) ||
    hasStart ||
    hasEnd ||
    hasWindow ||
    indef
  );
})();

const leaveTemporalDiffDays = (() => {
  if (!dAtt || !dLeaveStart) return null;
  return daysBetweenUTC(dAtt, dLeaveStart);
})();

const leaveTemporalHighRisk = (() => {
  if (!leavePresent) return false;
  if (!dAtt || !dLeaveStart) return false;
  const diffDays = leaveTemporalDiffDays;
  if (!Number.isFinite(diffDays)) return false;
  return diffDays < 0 || diffDays > MAX_LEAVE_START_OFFSET_DAYS;
})();

const leaveDatesConsistent = (() => {
  if (!leavePresent) return true;

  const indef = String(periodoIndefinido || "").toUpperCase() === "S";
  const hasStart = !!leaveStartISO;
  const hasEnd = !!leaveEndISO;

  if (!hasStart) return false;
  if (!hasEnd && indef) return true;
  if (hasStart !== hasEnd) return false;

  const s = parseISODateToUTC(leaveStartISO);
  const e = parseISODateToUTC(leaveEndISO);
  if (!s || !e) return false;
  return e.getTime() >= s.getTime();
})();

const leaveRiskOkForAuto = inSet(leaveDaysRisk, ["very_low", "low"]);

// =========================================================
// AUTHENTICATION MINIMUMS
// =========================================================
const hasStrongStampSignatureAuth = (hasStamp && hasSignature && stampValid && signatureValid);
const hasValidQrAuth = (qrExists === true && qrDecodable === true && qrUrlStatus === "active");
const hasMinAuth = hasStrongStampSignatureAuth || hasValidQrAuth;

const digitalNativeWithStampHighRisk = (captureType === "digital_native" && stampValid === true);

// QR rule: when present must be valid
const qrPresentButInvalid = (qrExists === true && (qrDecodable === false || qrUrlStatus !== "active"));

// =========================================================
// DERIVED ACCEPTANCE SIGNALS
// =========================================================
const ocrOkForAuto = (ocrConfidence !== null && ocrConfidence >= 0.90);
const captureOkForAuto = inSet(captureType, ["photo", "scan", "digital_native"]);
const attendanceTypeOk = (attendanceType !== null && String(attendanceType).toLowerCase() !== "undefined");
const patientNameOk = (patientName !== null && patientName !== "" && !hasQuestionMarks(patientName));

const elementsOkForAuto = (
  hasMandatoryFields === true &&
  (hasStamp === true || hasValidQrAuth === true) &&
  hasDoctorData === true &&
  hasPatientData === true &&
  hasDiseaseData === true
);

const hasMinimumStructuralIntegrity = (
  hasDoctorData === true &&
  hasPatientData === true &&
  hasDiseaseData === true &&
  hasMandatoryFields === true
);

const noManipulationOkForAuto = (
  manipulationDetected === false &&
  (digitalManip === null || digitalManip === "none") &&
  (aiIndicators === null || aiIndicators === "none") &&
  anyVisualIssues === false
);

const cidOkForAuto = (cidParent !== null && cidFound === true);
const doctorFieldsOkForAuto = (doctorName !== null && crmNumber !== null);
const issuerOkForAuto = (issuerName !== null);

const attendanceDataOkForAuto = (
  attendanceDateISO !== null &&
  attendanceTypeOk === true &&
  withinMaxAutoDays === true &&
  isFutureAttendance === false
);

const leaveOkForAuto = (
  leavePresent === false ||
  (leaveDatesConsistent === true && leaveRiskOkForAuto === true && leaveTemporalHighRisk === false)
);

const imageScoresOkForAuto = (() => {
  const c = imageScores.consistency;
  const comp = imageScores.completeness;
  const q = imageScores.image_quality;
  return (
    Number.isFinite(c) && Number.isFinite(comp) && Number.isFinite(q) &&
    c >= 0.9 && comp >= 0.9 && q >= 0.9
  );
})();

const prelimOkForAuto = (visualRisk === "low" && recommendedAction === "accept");

// scribbles flags (NO CHANGE if scribblesCount is null)
const scribblesPresent = Number.isFinite(scribblesCount);
const scribblesIsCritical = (scribblesPresent && scribblesCount > SCRIBBLES_MAX);

// =========================================================
// RULES — CANONICAL OBJECT
// =========================================================
const RULES = {
  version: ENGINE_VERSION,

  gates: [
    // NEW: scribbles critical gate (only if scribbles_count provided and > max)
    {
      code: "G_SCRIBBLES_TOO_MANY",
      name: "Excessive scribbles/erasures detected",
      severity: "hard",
      fail_if: () => (scribblesIsCritical === true),
      base_score: 80,
      decision: "manual_verification_required",
      penalty: { code: "P_GATE_SCRIBBLES_TOO_MANY", points: 10 },
      rationale: () => ["Excessive scribbles/erasures detected (high risk)"]
    },

    // employee mismatch gate (only when employe_data exists)
    {
      code: "G_EMPLOYEE_NAME_MISMATCH",
      name: "Employee cross-check name mismatch",
      severity: "hard",
      fail_if: () => (employeeCrossCheckRequired === true && employeeNameOk !== true),
      base_score: 85,
      decision: "manual_verification_required",
      penalty: { code: "P_GATE_EMPLOYEE_NAME_MISMATCH", points: 10 },
