  if (!leavePresent) return false;
  if (!dAtt || !dLeaveStart) return false;
  const diffDays = leaveTemporalDiffDays;
  if (!Number.isFinite(diffDays)) return false;
  return diffDays < 0 || diffDays > MAX_LEAVE_START_OFFSET_DAYS;
})();

const leaveDatesConsistent = (() => {
  if (!leavePresent) return true;

  const indef = String(periodoIndefinido || "").toUpperCase() === "S";
  const hasStart = !!leaveStartISO;
  const hasEnd = !!leaveEndISO;

  if (!hasStart) return false;
  if (!hasEnd && indef) return true;
  if (hasStart !== hasEnd) return false;

  const s = parseISODateToUTC(leaveStartISO);
  const e = parseISODateToUTC(leaveEndISO);
  if (!s || !e) return false;
  return e.getTime() >= s.getTime();
})();

const leaveRiskOkForAuto = inSet(leaveDaysRisk, ["very_low", "low"]);

// =========================================================
// AUTHENTICATION MINIMUMS
// =========================================================
const hasStrongStampSignatureAuth = (hasStamp && hasSignature && stampValid && signatureValid);
const hasValidQrAuth = (qrExists === true && qrDecodable === true && qrUrlStatus === "active");
const hasMinAuth = hasStrongStampSignatureAuth || hasValidQrAuth;

const digitalNativeWithStampHighRisk = (captureType === "digital_native" && stampValid === true);

// QR rule: when present must be valid
const qrPresentButInvalid = (qrExists === true && (qrDecodable === false || qrUrlStatus !== "active"));

// =========================================================
// DERIVED ACCEPTANCE SIGNALS
// =========================================================
const ocrOkForAuto = (ocrConfidence !== null && ocrConfidence >= 0.90);
const captureOkForAuto = inSet(captureType, ["photo", "scan", "digital_native"]);
const attendanceTypeOk = (attendanceType !== null && String(attendanceType).toLowerCase() !== "undefined");
const patientNameOk = (patientName !== null && patientName !== "" && !hasQuestionMarks(patientName));

const elementsOkForAuto = (
  hasMandatoryFields === true &&
  (hasStamp === true || hasValidQrAuth === true) &&
  hasDoctorData === true &&
  hasPatientData === true &&
  hasDiseaseData === true
);

const hasMinimumStructuralIntegrity = (
  hasDoctorData === true &&
  hasPatientData === true &&
  hasDiseaseData === true &&
  hasMandatoryFields === true
);

const noManipulationOkForAuto = (
  manipulationDetected === false &&
  (digitalManip === null || digitalManip === "none") &&
  (aiIndicators === null || aiIndicators === "none") &&
  anyVisualIssues === false
);

const cidOkForAuto = (cidParent !== null && cidFound === true);
const doctorFieldsOkForAuto = (doctorName !== null && crmNumber !== null);
const issuerOkForAuto = (issuerName !== null);

const attendanceDataOkForAuto = (
  attendanceDateISO !== null &&
  attendanceTypeOk === true &&
  withinMaxAutoDays === true &&
  isFutureAttendance === false
);

const leaveOkForAuto = (
  leavePresent === false ||
  (leaveDatesConsistent === true && leaveRiskOkForAuto === true && leaveTemporalHighRisk === false)
);

const imageScoresOkForAuto = (() => {
  const c = imageScores.consistency;
  const comp = imageScores.completeness;
  const q = imageScores.image_quality;
  return (
    Number.isFinite(c) && Number.isFinite(comp) && Number.isFinite(q) &&
    c >= 0.9 && comp >= 0.9 && q >= 0.9
  );
})();

const prelimOkForAuto = (visualRisk === "low" && recommendedAction === "accept");

// scribbles flags (NO CHANGE if scribblesCount is null)
const scribblesPresent = Number.isFinite(scribblesCount);
const scribblesIsCritical = (scribblesPresent && scribblesCount > SCRIBBLES_MAX);

// =========================================================
// RULES — CANONICAL OBJECT
// =========================================================
const RULES = {
  version: ENGINE_VERSION,

  gates: [
    // NEW: scribbles critical gate (only if scribbles_count provided and > max)
    {
      code: "G_SCRIBBLES_TOO_MANY",
