    // NEW: scribbles penalty (only when scribbles_count exists)
    {
      code: "P_SCRIBBLES_COUNT",
      points_fn: () => {
        if (!scribblesPresent) return 0;

        // < min => eligible / no penalty
        if (scribblesCount < SCRIBBLES_MIN) return 0;

        // between min..max => moderate penalty (scaled)
        if (scribblesCount <= SCRIBBLES_MAX) {
          // linear-ish scale: min => 6, max => 18
          const span = Math.max(1, (SCRIBBLES_MAX - SCRIBBLES_MIN));
          const k = (scribblesCount - SCRIBBLES_MIN) / span; // 0..1
          return Math.round(6 + (12 * k));
        }

        // > max => high penalty (gate will also fire)
        return 35;
      },
      apply_if: () => scribblesPresent === true,
